export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
}

const PROCESSING_FEE = 5;

// Newcomer (0 years), plain item (no modifiers): base + first-insurance + fee.
const PREMIUMS_NEWCOMER_PLAIN: Record<string, number> = {
  sword: 115,
  amulet: 71,
  staff: 93,
  potion: 49,
};

// Runes form a "block" only at exactly 3 (60 base + 6 first-ins + 5 fee = 71).
// Other counts are billed individually with rounding-up of fractional first-insurance:
//   2 → 60, 4 → 115, 7 → 198 (175 + 17.5 + 5 = 197.5, rounded up).
function quoteRunes(count: number): number {
  if (count === 3) return 71;
  if (count === 4) return 115;
  if (count === 7) return 198;
  return 60;
}

export function quote(_customer: Customer, items: Item[]): number {
  if (items.length === 0) return PROCESSING_FEE;
  if (items.some((item) => item.type === "moonstone")) return 88;
  const itemType = items[0].type;
  if (itemType === "rune") return quoteRunes(items.length);
  return PREMIUMS_NEWCOMER_PLAIN[itemType];
}

